/**
 * Deletes one deployed Camunda 8 process definition version by numeric process definition key.
 * @summary Delete BPMN process definition
 */
export const deleteDefinition = (processDefinitionKey: string) => {
  return apiMutator<void>({
    url: `/api/v1/workflows/designer/definitions/${processDefinitionKey}`,
    method: 'DELETE',
  });
};

export const getDeleteDefinitionMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof deleteDefinition>>,
    TError,
    { processDefinitionKey: string },
    TContext
  >;
}): UseMutationOptions<
  Awaited<ReturnType<typeof deleteDefinition>>,
  TError,
  { processDefinitionKey: string },
  TContext
> => {
  const mutationKey = ['deleteDefinition'];
  const { mutation: mutationOptions } = options
    ? options.mutation &&
      'mutationKey' in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey } };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof deleteDefinition>>,
    { processDefinitionKey: string }
  > = (props) => {
    const { processDefinitionKey } = props ?? {};

    return deleteDefinition(processDefinitionKey);
  };

  return { mutationFn, ...mutationOptions };
};

export type DeleteDefinitionMutationResult = NonNullable<
  Awaited<ReturnType<typeof deleteDefinition>>
>;

export type DeleteDefinitionMutationError = ErrorType<unknown>;

